           ELSE 'FAIL'
       END AS status
FROM dev.ba_ecommerce.renewals_360_agg
GROUP BY analysis_type;
-- Expected: Both analysis types should have positive totals

-- Check 8.2: Verify renewal rate is within reasonable bounds (0-100%)
SELECT 'Aggregate Check' AS validation_type,
       'Renewal Rate by Analysis Type' AS check_description,
       analysis_type,
       SUM(expiry_qty) AS total_expiries,
       SUM(renewal_qty) AS total_renewals,
       CASE 
           WHEN SUM(expiry_qty) > 0 
           THEN ROUND(100.0 * SUM(renewal_qty) / SUM(expiry_qty), 2)
           ELSE 0 
       END AS renewal_rate_pct,
       CASE 
           WHEN SUM(expiry_qty) = 0 THEN 'FAIL - No expiries'
           WHEN SUM(renewal_qty) / NULLIF(SUM(expiry_qty), 0) BETWEEN 0 AND 1.5 THEN 'PASS'
           ELSE 'WARN - Rate outside expected range'
       END AS status
FROM dev.ba_ecommerce.renewals_360_agg
GROUP BY analysis_type;
-- Expected: renewal_rate_pct between 0% and 150% (some tolerance for renewals)

-- Check 8.3: Daily totals match rolled-up weekly totals (sample check)
SELECT 'Aggregate Check' AS validation_type,
