FROM dev.ba_ecommerce.renewals_360_agg
WHERE renewal_bill_gcr_usd_amt < 0;
-- Expected: negative_count = 0 or very small (refunds may exist)

-- Check 8.5: Verify totals between renewals_360_agg and renewals_rate_mix_agg
SELECT 'Aggregate Check' AS validation_type,
