       '360_agg' AS source_table,
       SUM(expiry_qty) AS total_expiries,
       SUM(renewal_qty) AS total_renewals,
       SUM(renewal_bill_gcr_usd_amt) AS total_gcr
FROM dev.ba_ecommerce.renewals_360_agg
UNION ALL
SELECT 'Aggregate Check' AS validation_type,
       'Totals Match - 360_agg vs rate_mix_agg' AS check_description,
       'rate_mix_agg' AS source_table,
       SUM(expiry_qty) AS total_expiries,
       SUM(renewal_qty) AS total_renewals,
       SUM(renewal_bill_gcr_usd_amt) AS total_gcr
FROM ba_ecommerce.renewals_rate_mix_agg;
-- Expected: Totals should match between tables

-- Check 8.6: Month-to-date tracking validation
SELECT 'Aggregate Check' AS validation_type,
