       DATE_TRUNC('month', bill_mst_date) AS month,
       COUNT(DISTINCT bill_mst_date) AS days_with_data,
       SUM(expiry_qty) AS mtd_expiries,
       SUM(renewal_qty) AS mtd_renewals,
       CASE 
           WHEN COUNT(DISTINCT bill_mst_date) > 0 THEN 'PASS'
           ELSE 'FAIL'
       END AS status
FROM dev.ba_ecommerce.renewals_360_agg
WHERE bill_mst_date >= DATE_TRUNC('month', CURRENT_DATE)
GROUP BY DATE_TRUNC('month', bill_mst_date);
-- Expected: days_with_data should match days elapsed in current month

-- ================================================================
-- SECTION 9: JOB ALERT TABLE VALIDATION
-- ================================================================

-- Check 9.1: Validate renewal_job_alerts has success records
