           ELSE 'FAIL'
       END AS validation_status
FROM dev.ba_ecommerce.renewal_job_alerts
WHERE job_name IN ('Renewals Fixed Mix Adjusted', 'Renewals Overview Agg')
  AND run_ts = (SELECT MAX(run_ts) FROM dev.ba_ecommerce.renewal_job_alerts);
-- Expected: status = 'SUCCESS' for both jobs

-- Check 9.2: Verify data_expected_date matches actual max dates
SELECT 'Job Alert Check' AS validation_type,
       'Data Freshness Validation' AS check_description,
       j.dataset_name,
       j.max_date AS alert_max_date,
       j.data_expected_date,
       CASE j.dataset_name
           WHEN 'Renewals Overview Agg' THEN (SELECT MAX(bill_mst_date) FROM ba_ecommerce.renewals_rate_mix_agg)
           WHEN 'Renewals Fixed Mix Adjusted' THEN (SELECT MAX(as_of_date) FROM ba_ecommerce.renewal_fixed_rate_mix_adjusted_QS)
       END AS actual_max_date,
       CASE 
           WHEN j.max_date >= j.data_expected_date THEN 'PASS'
           ELSE 'FAIL'
       END AS status
FROM dev.ba_ecommerce.renewal_job_alerts j
WHERE j.job_name IN ('Renewals Fixed Mix Adjusted', 'Renewals Overview Agg')
  AND j.run_ts = (SELECT MAX(run_ts) FROM dev.ba_ecommerce.renewal_job_alerts);
-- Expected: alert_max_date = actual_max_date = data_expected_date

-- ================================================================
-- SECTION 10: SUMMARY VALIDATION REPORT
-- ================================================================

-- Check 10.1: Overall summary of key metrics
