       COUNT(DISTINCT analysis_type) AS analysis_types,
       COUNT(*) AS total_records,
       SUM(expiry_qty) AS total_expiries,
       SUM(renewal_qty) AS total_renewals,
       ROUND(100.0 * SUM(renewal_qty) / NULLIF(SUM(expiry_qty), 0), 2) AS overall_renewal_rate_pct,
