       MAX(bill_mst_date) AS latest_date,
       CASE 
           WHEN MAX(bill_mst_date) = CURRENT_DATE - 1 THEN 'PASS'
           ELSE 'FAIL'
       END AS data_freshness_status
FROM dev.ba_ecommerce.renewals_360_agg;
-- Expected: latest_date = CURRENT_DATE - 1, all metrics > 0

-- ================================================================
-- END OF VALIDATION SCRIPT
-- ================================================================
